1	import {
2	  DEFAULT_ACCOUNT_ID,
3	  normalizeAccountId,
4	  normalizeOptionalAccountId,
5	} from "openclaw/plugin-sdk/account-id";
6	import {
7	  listCombinedAccountIds,
8	  resolveListedDefaultAccountId,
9	} from "openclaw/plugin-sdk/account-resolution";
10	import { normalizeSecretInputString, type SecretInput } from "openclaw/plugin-sdk/secret-input";
11	import type { OpenClawConfig } from "../api.js";
12	import type { NostrProfile } from "./config-schema.js";
13	import { DEFAULT_RELAYS } from "./default-relays.js";
14	import { getPublicKeyFromPrivate } from "./nostr-bus.js";
15	
16	export interface NostrAccountConfig {
17	  enabled?: boolean;
18	  name?: string;
19	  defaultAccount?: string;
20	  privateKey?: SecretInput;
21	  relays?: string[];
22	  dmPolicy?: "pairing" | "allowlist" | "open" | "disabled";
23	  allowFrom?: Array<string | number>;
24	  profile?: NostrProfile;
25	}
26	
27	export interface ResolvedNostrAccount {
28	  accountId: string;
29	  name?: string;
30	  enabled: boolean;
31	  configured: boolean;
32	  privateKey: string;
33	  publicKey: string;
34	  relays: string[];
35	  profile?: NostrProfile;
36	  config: NostrAccountConfig;
37	}
