72	/**
73	 * Resolve a Nostr account from config
74	 */
75	export function resolveNostrAccount(opts: {
76	  cfg: OpenClawConfig;
77	  accountId?: string | null;
78	}): ResolvedNostrAccount {
79	  const accountId = normalizeAccountId(opts.accountId ?? resolveDefaultNostrAccountId(opts.cfg));
80	  const nostrCfg = (opts.cfg.channels as Record<string, unknown> | undefined)?.nostr as
81	    | NostrAccountConfig
82	    | undefined;
83	
84	  const baseEnabled = nostrCfg?.enabled !== false;
85	  const privateKey = normalizeSecretInputString(nostrCfg?.privateKey) ?? "";
86	  const configured = Boolean(privateKey);
87	
88	  let publicKey = "";
89	  if (privateKey) {
90	    try {
91	      publicKey = getPublicKeyFromPrivate(privateKey);
92	    } catch {
93	      // Invalid key - leave publicKey empty, configured will indicate issues
94	    }
95	  }
96	
97	  return {
98	    accountId,
99	    name: nostrCfg?.name?.trim() || undefined,
100	    enabled: baseEnabled,
101	    configured,
102	    privateKey,
103	    publicKey,
104	    relays: nostrCfg?.relays ?? DEFAULT_RELAYS,
105	    profile: nostrCfg?.profile,
106	    config: {
107	      enabled: nostrCfg?.enabled,
108	      name: nostrCfg?.name,
109	      privateKey: nostrCfg?.privateKey,
110	      relays: nostrCfg?.relays,
111	      dmPolicy: nostrCfg?.dmPolicy,
112	      allowFrom: nostrCfg?.allowFrom,
113	      profile: nostrCfg?.profile,
114	    },
115	  };
116	}
